import{_ as i,o as a,c as e,ag as t}from"./chunks/framework.BVZs_YW1.js";const c=JSON.parse('{"title":"Btrfs 在线迁移系统到新分区","description":"","frontmatter":{},"headers":[],"relativePath":"notes/system/btrfs-online-migration.md","filePath":"notes/system/btrfs-online-migration.md"}'),l={name:"notes/system/btrfs-online-migration.md"};function n(h,s,p,d,o,r){return a(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="btrfs-在线迁移系统到新分区" tabindex="-1">Btrfs 在线迁移系统到新分区 <a class="header-anchor" href="#btrfs-在线迁移系统到新分区" aria-label="Permalink to &quot;Btrfs 在线迁移系统到新分区&quot;">​</a></h1><p>这个场景很适合 Btrfs：</p><ul><li>磁盘前面腾出了一大块未分配空间</li><li>原系统在磁盘尾部</li><li>旧 ESP 太小</li><li>不想进 LiveCD，也不想重启</li></ul><h2 id="_1-先规划新分区" tabindex="-1">1. 先规划新分区 <a class="header-anchor" href="#_1-先规划新分区" aria-label="Permalink to &quot;1. 先规划新分区&quot;">​</a></h2><p>用 GParted 之类的工具在磁盘前面新建：</p><ol><li>一个 <code>1024 MiB</code> 的 <code>fat32</code> 分区，准备用作新 ESP</li><li>一个新的 <code>btrfs</code> 分区，吃掉剩下的空间</li></ol><h2 id="_2-在线把数据搬过去" tabindex="-1">2. 在线把数据搬过去 <a class="header-anchor" href="#_2-在线把数据搬过去" aria-label="Permalink to &quot;2. 在线把数据搬过去&quot;">​</a></h2><p>系统还在运行时，直接做：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> btrfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> device</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nvme1n1p_NEW</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> btrfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> device</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nvme1n1p_OLD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span></span></code></pre></div><p><code>device remove</code> 开始之后，Btrfs 会在后台把数据从旧分区搬到新分区。</p><h2 id="_3-清理旧分区并扩容" tabindex="-1">3. 清理旧分区并扩容 <a class="header-anchor" href="#_3-清理旧分区并扩容" aria-label="Permalink to &quot;3. 清理旧分区并扩容&quot;">​</a></h2><p>搬完以后：</p><ol><li>删除旧的 ESP 和旧的 Btrfs 分区</li><li>把新的 Btrfs 分区拉伸到吃满剩余空间</li><li>通知 Btrfs 认领新容量</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> btrfs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> filesystem</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> resize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> max</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span></span></code></pre></div><h2 id="_4-修-fstab-和挂载新的-esp" tabindex="-1">4. 修 <code>fstab</code> 和挂载新的 ESP <a class="header-anchor" href="#_4-修-fstab-和挂载新的-esp" aria-label="Permalink to &quot;4. 修 `fstab` 和挂载新的 ESP&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blkid</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nvme1n1p_NEW_ESP</span></span></code></pre></div><p>拿到新的 UUID 之后：</p><ol><li>改 <code>/etc/fstab</code></li><li>把 <code>/efi</code> 的 UUID 替换成新值</li><li>挂载新 ESP</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mount</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/nvme1n1p_NEW_ESP</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /efi</span></span></code></pre></div><p>最后再按你自己的引导方式修引导。</p>',20)])])}const F=i(l,[["render",n]]);export{c as __pageData,F as default};
